import Vue from 'vue'
import Buefy from 'buefy'
import 'buefy/dist/buefy.css'
import App from './App.vue'
import router from './router'
import store from './store'
import './registerServiceWorker'
import axios from 'axios'

// ####components####
import toPage from './components/page-button.vue'
import messageModal from './components/message-modal.vue'
import headings from './components/headings.vue'
Vue.component('headings', headings)
Vue.component('message-modal', messageModal)
Vue.component('to-page', toPage)

Vue.use(axios)
Vue.use(Buefy, {
  defaultIconPack: 'fas',
  defaultContainerElement: '#forms-app',
  defaultDaynames: ['Sun', 'Mon', 'Tue', 'Wed', 'Thu', 'Fri', 'Sat'],
  defaultDateFormatter: function(date) {
      var newDate = date.toLocaleDateString("en-US", {
        weekday: 'short', year: 'numeric', month: 'long', day: 'numeric'
      })
      return newDate;
  }
})

new Vue({
  router,
  store,
  render: h => h(App)
}).$mount('#forms-app')

Vue.config.productionTip = true