<template>

  <div class="section">
    <headings :page="page" :heading="heading" progress="25" @toggled="toggled = !toggled"></headings>

    <message-modal :toggled="toggled" @toggled="toggled = !toggled">
      <p class="is-size-4 has-text-primary" slot="title">Provide Us with Details on the Property You're Buying</p>
      <p slot="message">
        Please elaborate on the costs and details of the property you are looking to mortgage.
      </p>
      <p slot="message" class="is-size-5 is-size-6-mobile">
        This page inquires about the following form items:
      </p>
      <ul slot="list">
        <li>Realtor's quote price</li>
        <li>Your downpayment amount</li>
        <li>Your estimated annual property costs</li>
        <li>Any documents you've signed</li>
        <li v-if="$store.state.PropertyForm.offerMade">Terms of your contract</li>
      </ul>
    </message-modal>

    <div class="container">
      <div class="box">
        <div class="columns is-centered">
          <div class="column is-half is-one-third-desktop">
            <b-field label="Purchase price" :addons="false" class="info">
              <b-tooltip label="Quoted by your realtor or on the MLS listing" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="purchasePrice" icon="dollar-sign" placeholder="CAD"></b-input>
            </b-field>
          </div>
          <div class="column is-half is-one-third-desktop">
            <b-field label="Downpayment" :addons="false" class="info">
              <b-tooltip label="Maximum amount you can put down at this time" position="is-left" size="is-medium" type="is-dark" animated multilined>
                <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
              </b-tooltip>
              <b-input v-model="downpayment" icon="dollar-sign" placeholder="CAD"></b-input>
            </b-field>
          </div>
        </div>

        <div class="columns is-centered">
          <div class="column is-two-thirds-desktop">
            <div class="columns is-multiline is-centered">
              <div class="column is-half">
                <b-field label="Property taxes" :addons="false" class="info">
                  <b-tooltip label="Estimated annual cost based on property value" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-input v-model="propertyTaxes" icon="dollar-sign" placeholder="CAD / year"></b-input>
                </b-field>
              </div>
              <div class="column is-half" v-if="$store.state.StartForm.occupancyType === 'rental'">
                <b-field label="Expected rental income" :addons="false" class="info">
                  <b-tooltip label="What do you expect to charge per month?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-input icon="dollar-sign" placeholder="CAD / month"></b-input>
                </b-field>
              </div>
              <div class="column is-half">
                <b-field label="Offer made" :addons="false" class="info">
                  <b-tooltip label="Have you signed the documents with your realtor?" position="is-left" size="is-medium" type="is-dark" animated multilined>
                    <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                  </b-tooltip>
                  <b-select placeholder="With your realtor" expanded icon="handshake" v-model="offerMade">
                    <option :value="true">Yes</option>
                    <option :value="false">No</option>
                  </b-select>
                </b-field>
              </div>
            </div>
          </div>
        </div>

        <transition name="fadeUp" mode="out-in">
          <div class="columns is-centered" v-if="offerMade">
            <div class="column is-half is-one-third-desktop">
              <b-field label="Closing date" :addons="false" class="info">
                <b-tooltip label="Listed in the terms of your contract" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-datepicker v-model="closingDate" placeholder="Click for calendar" icon="calendar-alt">
                </b-datepicker>
              </b-field>
            </div>
            <div class="column is-half is-one-third-desktop">
              <b-field label="Financial conditions date" :addons="false" class="info">
                <b-tooltip label="Listed in the terms of your contract" position="is-left" size="is-medium" type="is-dark" animated multilined>
                  <i class="fas fa-question-circle" role="note" aria-label="additional info" title="Info"></i>
                </b-tooltip>
                <b-datepicker v-model="conditionsDate" placeholder="Click for calendar" icon="calendar-alt">
                </b-datepicker>
              </b-field>
            </div>
          </div>
        </transition>

        <address-block :form="$store.state.PropertyForm.address" message="Address of the property" icon="home"></address-block>

        <to-page back="'-1'" next="/personal" text="Go to Personal Info Form"></to-page>
      </div>
    </div>
  </div>
</template>

<script>
import addressBlock from "../components/address-block.vue";
export default {
  data() {
    return {
      page: "Page 2",
      heading: "Detailed Property Information",
      toggled: false
    };
  },
  computed: {
    offerMade: {
      get() {
        return this.$store.state.PropertyForm.offerMade;
      },
      set(val) {
        this.$store.state.PropertyForm.offerMade = val;
      }
    },
    closingDate: {
      get() {
        return this.$store.state.PropertyForm.closingDate;
      },
      set(val) {
        this.$store.state.PropertyForm.closingDate = val;
      }
    },
    conditionsDate: {
      get() {
        return this.$store.state.PropertyForm.conditionsDate;
      },
      set(val) {
        this.$store.state.PropertyForm.conditionsDate = val;
      }
    },
    purchasePrice: {
      get() {
        return this.$store.state.PropertyForm.purchasePrice;
      },
      set(val) {
        this.$store.state.PropertyForm.purchasePrice = val;
      }
    },
    downpayment: {
      get() {
        return this.$store.state.PropertyForm.downpayment;
      },
      set(val) {
        this.$store.state.PropertyForm.downpayment = val;
      }
    },
    propertyTaxes: {
      get() {
        return this.$store.state.PropertyForm.propertyTaxes;
      },
      set(val) {
        this.$store.state.PropertyForm.propertyTaxes = val;
      }
    },
    expectedRentalIncome: {
      get() {
        return this.$store.state.PropertyForm.expectedRentalIncome;
      },
      set(val) {
        this.$store.state.PropertyForm.expectedRentalIncome = val;
      }
    }
  },
  components: {
    addressBlock
  }
};
</script>